import hmac
import hashlib
from fastapi import Header, HTTPException

def hash_key(plaintext: str) -> str:
    return hashlib.sha256(plaintext.encode()).hexdigest()

def verify_api_key(presented: str, stored_hash: str) -> bool:
    return hmac.compare_digest(hash_key(presented), stored_hash)

async def api_key_dep(x_api_key: str = Header(...)):
    key = await db.api_keys.find_by_prefix(x_api_key[:8])
    if not key or not verify_api_key(x_api_key, key.hash):
        raise HTTPException(401, "Invalid API key")
    if key.revoked:
        raise HTTPException(401, "Key revoked")
    return key

from jose import jwt, JWTError
from datetime import datetime, timedelta, timezone

ALGORITHM = "RS256"
ACCESS_TOKEN_EXPIRE_MINUTES = 15

def create_access_token(data: dict, private_key: str) -> str:
    payload = data.copy()
    expire = datetime.now(timezone.utc) + timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
    payload.update({"exp": expire, "iat": datetime.now(timezone.utc)})
    return jwt.encode(payload, private_key, algorithm=ALGORITHM)

def verify_token(token: str, public_key: str, audience: str) -> dict:
    try:
        return jwt.decode(
            token, public_key,
            algorithms=[ALGORITHM],
            audience=audience,
        )
    except JWTError:
        raise HTTPException(401, "Invalid token")

SCOPES = {
    "read:users":   "Read user profiles",
    "write:users":  "Create and update users",
    "delete:users": "Delete users",
    "admin":        "Full administrative access",
}

def require_scope(required: str):
    def checker(token: dict = Depends(verify_token)):
        scopes = token.get("scope", "").split()
        if required not in scopes and "admin" not in scopes:
            raise HTTPException(403, f"Scope '{required}' required")
        return token
    return checker

@app.delete("/users/{user_id}")
async def delete_user(
    user_id: str,
    _: dict = Depends(require_scope("delete:users")),
